"use client";

import { useEffect, useRef } from "react";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { particleStore } from "@/lib/particleStore";

gsap.registerPlugin(ScrollTrigger);

/**
 * Scroll → phase mapping  (scroll-root = 300vh total)
 *
 *  0% –  12%  introProgress  0 → 1   (particles appear AT text positions)
 *  8% –  55%  scrollProgress 0 → 1   (particles disintegrate from text)
 * 55% –  65%  buffer (free-flying)
 * 65% – 100%  assemblyProgress 0 → 1 (sphere assembly)
 *
 * Hero title HTML fades out during intro 0→10%.
 */
export default function ScrollController() {
  const heroTitleRef = useRef<Element | null>(null);

  useEffect(() => {
    // Grab the h1 to animate its opacity via scroll
    heroTitleRef.current = document.querySelector("[data-hero-title]");

    const ctx = gsap.context(() => {
      ScrollTrigger.create({
        trigger: "#scroll-root",
        start: "top top",
        end: "bottom bottom",
        scrub: 1.6,
        onUpdate: (self) => {
          const p = self.progress;

          // ── Intro: particles fade in (scroll 0 → 12%) ─────────────────────
          const INTRO_S = 0.00, INTRO_E = 0.14;
          particleStore.introProgress =
            Math.min(1, Math.max(0, (p - INTRO_S) / (INTRO_E - INTRO_S)));

          // ── HTML title: fades out as particles appear ──────────────────────
          if (heroTitleRef.current) {
            const fade = Math.max(0, 1 - p / 0.10); // full opacity → 0 by 10%
            (heroTitleRef.current as HTMLElement).style.opacity = String(fade);
          }

          // ── Disintegration: text → noise flow (scroll 8% → 55%) ───────────
          const DIS_S = 0.08, DIS_E = 0.55;
          const ASM_S = 0.65, ASM_E = 1.00;

          if (p < DIS_S) {
            particleStore.scrollProgress   = 0;
            particleStore.assemblyProgress = 0;
          } else if (p <= DIS_E) {
            particleStore.scrollProgress   = (p - DIS_S) / (DIS_E - DIS_S);
            particleStore.assemblyProgress = 0;
          } else if (p < ASM_S) {
            particleStore.scrollProgress   = 1;
            particleStore.assemblyProgress = 0;
          } else {
            particleStore.scrollProgress   = 1;
            particleStore.assemblyProgress = (p - ASM_S) / (ASM_E - ASM_S);
          }
        },
      });
    });

    return () => ctx.revert();
  }, []);

  return null;
}
